{{(() => {
   const details = GetOrderDetails.data?.[0];
   if (!details) return '';

   const formatDate = (dateStr) => {
     if (!dateStr) return 'N/A';
     return moment(dateStr).format('MMM DD, YYYY HH:mm');
   };

   let statusInfo = '';
   if (details.delivered_at) {
     statusInfo = `Delivered on ${formatDate(details.delivered_at)}`;
   } else if (details.returned_at) {
     statusInfo = `Returned on ${formatDate(details.returned_at)}`;
   } else if (details.cancelled_at) {
     statusInfo = `Cancelled on ${formatDate(details.cancelled_at)}`;
   } else if (details.started_at) {
     statusInfo = `In Transit since ${formatDate(details.started_at)}`;
   } else if (details.dispatched_at) {
     statusInfo = `Dispatched on ${formatDate(details.dispatched_at)}`;
   } else {
     statusInfo = `Created on ${formatDate(details.created_at)}`;
   }

   return statusInfo;
 })()}}
